import os

# Find ALL image references in source code (tsx, ts, json)
r = terminal("cd /root/elviajero && grep -rn '/images/' app/ components/ --include='*.tsx' --include='*.ts' 2>/dev/null | grep -oP '/images/[\\w./-]+\\.(png|jpg|jpeg|webp|avif|svg)' | sort -u", timeout=15)
code_refs = set(r['output'].strip().split('\n'))
print("=== Images referenced in .tsx/.ts ===")
for x in sorted(code_refs): print(f"  {x}")

# Also from content/es.json
r2 = terminal("cd /root/elviajero && grep -oP '/images/[\\w./-]+\\.(png|jpg|jpeg|webp|avif|svg)' content/es.json | sort -u", timeout=15)
content_refs = set(r2['output'].strip().split('\n'))
print(f"\n=== Images referenced in content/es.json ===")
for x in sorted(content_refs): print(f"  {x}")

# Check if image files exist for each reference
print(f"\n=== MISSING FILES (referenced but not on disk) ===")
all_refs = code_refs | content_refs
for ref in sorted(all_refs):
    path = '/root/elviajero/public' + ref
    if not os.path.isfile(path):
        print(f"  ❌ {ref}")

# Check orphaned files on disk not referenced
print(f"\n=== ORPHANED FILES (on disk but not referenced) ===")
on_disk = set()
for root, dirs, files in os.walk('/root/elviajero/public'):
    dirs[:] = [d for d in dirs if d != 'dayah']  # skip dayah dir
    for f in files:
        if f.lower().endswith(('.png', '.jpg', '.jpeg', '.webp', '.avif', '.svg', '.ico')):
            rel = os.path.relpath(os.path.join(root, f), '/root/elviajero/public')
            on_disk.add('/' + rel)

# Also check root-level files like favicon.svg, og-default.png
for f in ['/favicon.svg', '/og-default.png', '/robots.txt', '/sitemap.xml']:
    path = '/root/elviajero/public' + f
    if os.path.isfile(path):
        on_disk.add(f)

orphaned = on_disk - all_refs
for x in sorted(orphaned):
    if 'dayah' not in x:
        sz = os.path.getsize('/root/elviajero/public' + x)
        print(f"  {x} ({sz} bytes)")
"}

